mapper.select:
SELECT COALESCE(SUM(danger_count + critical_count), 0) FROM dashboard_area_metric_daily WHERE area_id = #{areaId}
AND stat_date >= DATE(FROM_UNIXTIME(#{startTime}/1000))
AND stat_date <= DATE(FROM_UNIXTIME(#{endTime}/1000))

SELECT COALESCE(SUM(traffic_sum) / NULLIF(SUM(sample_count), 0), 0) AS ave_flow, COALESCE(SUM(pressure_sum) / NULLIF(SUM(sample_count), 0), 0) AS ave_pressure, COALESCE(SUM(temperature_sum) / NULLIF(SUM(sample_count), 0), 0) AS ave_temperature, COALESCE(SUM(shake_sum) / NULLIF(SUM(sample_count), 0), 0) AS ave_vibration, 0 AS time FROM dashboard_area_metric_daily WHERE area_id = #{areaId}
AND stat_date >= DATE(FROM_UNIXTIME(#{startTime}/1000))
AND stat_date <= DATE(FROM_UNIXTIME(#{endTime}/1000))

SELECT CAST(inspection_id AS CHAR) AS id, UNIX_TIMESTAMP(alarm_time) * 1000 AS time, CAST(sensor_id AS CHAR) AS sensor_id, sensor_name AS sensor_name, CAST(area_id AS CHAR) AS area_id, area_name AS area_name, message, level FROM dashboard_alarm_recent WHERE 1 = 1
AND area_id BETWEEN #{areaStart} AND #{areaEnd}
AND alarm_time >= FROM_UNIXTIME(#{startTime}/1000)
AND alarm_time <= FROM_UNIXTIME(#{endTime}/1000)
ORDER BY alarm_time DESC LIMIT #{limit}
